import { ApiAuthError, fetchRawJson } from 'spatial-id-svc-base';
/**
 * ログインを行い、成功時 AuthInfo オブジェクトを返す。
 * 認証失敗時は ApiAuthError 例外を発生させる。
 */
export const login = async ({ baseUrl, userID, organizationID, password, abortSignal, }) => {
    const resp = await fetchRawJson({
        method: 'POST',
        baseUrl,
        path: '/gen/api/generic/v3/connect-server',
        payload: {
            userID,
            // organizationID,
            password,
        },
        abortSignal,
    });
    if (resp.result !== 'COMPLETE') {
        throw new ApiAuthError('failed to authenticate');
    }
    return {
        username: userID,
        organizationID,
        token: resp.token,
    };
};
